/* Tailwind v4 theme mappings for violet-ui custom tokens.
   Standard shadcn tokens (--color-primary, etc.) are already mapped
   by the consumer's globals.css — this block adds violet-ui extras. */
@theme inline {
  /* Status tint colors (used by violet-status-badge) */
  --color-status-neutral: hsl(var(--status-neutral));
  --color-status-neutral-foreground: hsl(var(--status-neutral-foreground));
  --color-info-tint: hsl(var(--info-tint));
  --color-warning-tint: hsl(var(--warning-tint));
  --color-warning-tint-foreground: hsl(var(--warning-tint-foreground));
  --color-destructive-tint: hsl(var(--destructive-tint));
  --color-destructive-tint-foreground: hsl(var(--destructive-tint-foreground));
  --color-success-tint: hsl(var(--success-tint));
  --color-success-tint-foreground: hsl(var(--success-tint-foreground));
  --color-info-tint-foreground: hsl(var(--info-tint-foreground));

  /* Semantic colors not in standard shadcn */
  --color-success: hsl(var(--success));
  --color-success-foreground: hsl(var(--success-foreground));
  --color-warning: hsl(var(--warning));
  --color-warning-foreground: hsl(var(--warning-foreground));
  --color-info: hsl(var(--info));
  --color-info-foreground: hsl(var(--info-foreground));

  /* Layered shadows — resolved via CSS variable indirection for dark mode */
  --shadow-xs: var(--shadow-xs-val);
  --shadow-sm: var(--shadow-sm-val);
  --shadow-md: var(--shadow-md-val);
  --shadow-lg: var(--shadow-lg-val);
  --shadow-xl: var(--shadow-xl-val);
}

@layer base {
  :root {
    --background: 220 14% 96%;
    --foreground: 0 0% 20%;
    --card: 0 0% 100%;
    --card-foreground: 0 0% 20%;
    --popover: 0 0% 100%;
    --popover-foreground: 0 0% 20%;
    --primary: 275 90% 29%;
    --primary-foreground: 0 0% 100%;
    --secondary: 270 45% 52%;
    --secondary-foreground: 0 0% 100%;
    --muted: 220 14% 96%;
    --muted-foreground: 215 14% 46%;
    --accent: 280 30% 64%;
    --accent-foreground: 0 0% 100%;
    --destructive: 354 70% 54%;
    --destructive-foreground: 0 0% 100%;
    --success: 134 61% 41%;
    --success-foreground: 0 0% 100%;
    --warning: 45 100% 51%;
    --warning-foreground: 0 0% 20%;
    --info: 211 100% 50%;
    --info-foreground: 0 0% 100%;
    --border: 220 13% 91%;
    --input: 220 13% 91%;
    --ring: 275 90% 29%;
    --radius: 0.375rem;

    /* Shadow value tokens (light mode) */
    --shadow-xs-val: 0 1px 2px 0 rgb(0 0 0 / 0.03);
    --shadow-sm-val: 0 1px 2px 0 rgb(0 0 0 / 0.04), 0 1px 4px -1px rgb(0 0 0 / 0.07);
    --shadow-md-val: 0 2px 4px -1px rgb(0 0 0 / 0.06), 0 4px 8px -2px rgb(0 0 0 / 0.1);
    --shadow-lg-val: 0 4px 6px -2px rgb(0 0 0 / 0.05), 0 10px 22px -4px rgb(0 0 0 / 0.12);
    --shadow-xl-val: 0 8px 12px -4px rgb(0 0 0 / 0.05), 0 20px 40px -8px rgb(0 0 0 / 0.15);

    /* Status tint backgrounds (light bg + saturated text) */
    --status-neutral: 210 14% 93%;
    --status-neutral-foreground: 215 14% 46%;
    --info-tint: 207 88% 94%;
    --info-tint-foreground: 211 80% 38%;
    --warning-tint: 45 100% 90%;
    --warning-tint-foreground: 28 98% 54%;
    --destructive-tint: 354 71% 91%;
    --destructive-tint-foreground: 354 65% 42%;
    --success-tint: 134 41% 88%;
    --success-tint-foreground: 134 55% 30%;
  }

  .dark {
    --background: 270 10% 8%;
    --foreground: 0 0% 95%;
    --card: 270 10% 12%;
    --card-foreground: 0 0% 95%;
    --popover: 270 10% 12%;
    --popover-foreground: 0 0% 95%;
    --primary: 275 60% 65%;
    --primary-foreground: 270 90% 10%;
    --secondary: 270 30% 40%;
    --secondary-foreground: 0 0% 100%;
    --muted: 270 10% 15%;
    --muted-foreground: 270 5% 60%;
    --accent: 280 25% 50%;
    --accent-foreground: 0 0% 100%;
    --destructive: 354 70% 54%;
    --destructive-foreground: 0 0% 100%;
    --success: 134 61% 41%;
    --success-foreground: 0 0% 100%;
    --warning: 45 100% 51%;
    --warning-foreground: 0 0% 20%;
    --info: 211 100% 60%;
    --info-foreground: 0 0% 100%;
    --border: 270 10% 20%;
    --input: 270 10% 20%;
    --ring: 275 60% 65%;
    --radius: 0.375rem;

    /* Shadow value tokens (dark mode — higher opacity + subtle light ring) */
    --shadow-xs-val: 0 1px 2px 0 rgb(0 0 0 / 0.15), 0 0 0 1px rgb(255 255 255 / 0.04);
    --shadow-sm-val: 0 1px 3px 0 rgb(0 0 0 / 0.25), 0 0 0 1px rgb(255 255 255 / 0.05);
    --shadow-md-val: 0 2px 6px -1px rgb(0 0 0 / 0.35), 0 0 0 1px rgb(255 255 255 / 0.05);
    --shadow-lg-val: 0 4px 12px -2px rgb(0 0 0 / 0.45), 0 0 0 1px rgb(255 255 255 / 0.06);
    --shadow-xl-val: 0 8px 24px -4px rgb(0 0 0 / 0.5), 0 0 0 1px rgb(255 255 255 / 0.07);

    /* Status tint backgrounds (dark mode) */
    --status-neutral: 270 10% 18%;
    --status-neutral-foreground: 270 5% 60%;
    --info-tint: 211 60% 18%;
    --info-tint-foreground: 211 90% 72%;
    --warning-tint: 45 60% 18%;
    --warning-tint-foreground: 28 90% 60%;
    --destructive-tint: 354 50% 18%;
    --destructive-tint-foreground: 354 75% 68%;
    --success-tint: 134 40% 18%;
    --success-tint-foreground: 134 50% 62%;
  }
}
